content.text:
[
  {
    "ruleId": "R10",
    "pass": false,
    "severity": "advisory",
    "evidence": "beat-01's visual is two number columns (schematic-numeric, not a concrete picture) that simply cut to beat-02's arrows ('One amber probe arrow and four periwinkle candidate arrows appear'); no morph is staged connecting the number-list representation to the arrow representation, so the concrete->schematic fade required by the rule is never shown even though the schematic->symbolic fade later (the mint glow a.b truing up) is.",
    "suggestion": "have the number-column entries visibly rotate/collapse into the probe and candidate arrows at the top of beat-02 so the first representational jump is animated, not cut."
  },
  {
    "ruleId": "R2",
    "pass": false,
    "severity": "advisory",
    "evidence": "beat-04 narration makes two parallel claims, 'Long songs would win on sheer loudness, and padded resumes would win on sheer length,' but the visual at that moment ('One periwinkle candidate stretches longer... a small rose flag marks the unearned win') is staged entirely inside the already-swapped job-posting scene; the song-domain half of the claim has no visual referent on screen.",
    "suggestion": "either cut the song-domain restatement from the narration or briefly flash back to a stretching song-candidate arrow before returning to the job aisle."
  },
  {
    "ruleId": "R3",
    "pass": false,
    "severity": "advisory",
    "evidence": "the locked registry assigns amber to the probe and periwinkle to candidates, but beat-03's notation is described as 'a small periwinkle mono annotation, a . b,' rendering both the probe term (a) and candidate term (b) in a single color instead of color-matching each symbol to its referent.",
    "suggestion": "split the annotation coloring so 'a' renders in amber and 'b' in periwinkle, consistent with the rest of the session's term-to-referent color coding."
  },
  {
    "ruleId": "R8",
    "pass": false,
    "severity": "advisory",
    "evidence": "beat-02's stage direction reads 'One amber probe arrow and four periwinkle candidate arrows appear' — 'appear' is a display verb, not a build verb, at exactly the moment the plan-level check asks to be verified (intents must say draws/builds).",
    "suggestion": "rewrite the intent so the probe and candidates are drawn in sequence (e.g., probe arrow drawn first, then candidates drawn one at a time), matching the reasoning order in which they're used."
  }
]

